import{c as a,Q as i,j as t,m as l}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"An LLM Compiler for Parallel Function Calling","description":"","frontmatter":{"title":"An LLM Compiler for Parallel Function Calling","arxiv_id":2312.04511,"authors":"Sehoon Kim, Suhong Moon, Ryan Tabrizi, Nicholas Lee, Michael W. Mahoney, Kurt Keutzer, Amir Gholami","fetched":"2026-05-12T00:00:00.000Z","published":"2024-06-05T00:00:00.000Z","source":"https://arxiv.org/abs/2312.04511","source_tier":"P","venue":"ICML 2024"},"headers":[],"relativePath":"research/papers/2026-05-12-llmcompiler-icml-2024-2312-04511.md","filePath":"research/papers/2026-05-12-llmcompiler-icml-2024-2312-04511.md","lastUpdated":1779901665000}'),n={name:"research/papers/2026-05-12-llmcompiler-icml-2024-2312-04511.md"};function o(r,e,s,c,p,h){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="an-llm-compiler-for-parallel-function-calling" tabindex="-1">An LLM Compiler for Parallel Function Calling <a class="header-anchor" href="#an-llm-compiler-for-parallel-function-calling" aria-label="Permalink to &quot;An LLM Compiler for Parallel Function Calling&quot;">​</a></h1><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>The researchers present LLMCompiler, a system that enables language models to execute multiple function calls simultaneously rather than sequentially. Inspired by classical compiler design, the approach uses three components: a planner that formulates execution strategies, a task dispatcher, and a parallel executor.</p><p>According to their findings, the system achieves &quot;latency speedup of up to 3.7x, cost savings of up to 6.7x&quot; when compared to ReAct, while also improving accuracy margins. This represents a significant advancement in agent efficiency and cost-effectiveness.</p><hr><h2 id="problem-statement" tabindex="-1">Problem Statement <a class="header-anchor" href="#problem-statement" aria-label="Permalink to &quot;Problem Statement&quot;">​</a></h2><p>While multi-function calling allows LLMs to tackle more complex problems, current methods often require sequential reasoning and acting for each function which can result in:</p><ul><li>High latency (waiting for each function to complete before reasoning about the next)</li><li>High cost (token consumption due to sequential processing)</li><li>Sometimes inaccurate behavior (lack of parallelization awareness)</li></ul><hr><h2 id="core-innovation" tabindex="-1">Core Innovation <a class="header-anchor" href="#core-innovation" aria-label="Permalink to &quot;Core Innovation&quot;">​</a></h2><p>LLMCompiler addresses sequential function-calling limitations by automatically orchestrating parallel execution. The system design is inspired by classical compiler theory, decomposing the problem into multiple phases:</p><h3 id="three-component-architecture" tabindex="-1">Three-Component Architecture <a class="header-anchor" href="#three-component-architecture" aria-label="Permalink to &quot;Three-Component Architecture&quot;">​</a></h3><ol><li><p><strong>Function Calling Planner:</strong> Formulates execution plans for function calling</p><ul><li>Analyzes which tasks can be performed in parallel</li><li>Identifies interdependencies between tasks</li><li>Generates optimal execution strategies</li></ul></li><li><p><strong>Task Fetching Unit:</strong> Dispatches function calling tasks</p><ul><li>Manages task queue</li><li>Handles dependencies</li><li>Ensures correct execution order</li></ul></li><li><p><strong>Executor:</strong> Executes tasks in parallel</p><ul><li>Runs independent tasks simultaneously</li><li>Manages resource allocation</li><li>Handles task completion and result aggregation</li></ul></li></ol><hr><h2 id="key-technical-contributions" tabindex="-1">Key Technical Contributions <a class="header-anchor" href="#key-technical-contributions" aria-label="Permalink to &quot;Key Technical Contributions&quot;">​</a></h2><ol><li><p><strong>Automatic Parallelization Detection:</strong> The planner automatically identifies which tasks can be performed in parallel versus which have data dependencies</p></li><li><p><strong>Compiler-Inspired Design:</strong> Application of compiler theory principles (dependency analysis, scheduling) to LLM-based task execution</p></li><li><p><strong>Multi-Model Compatibility:</strong> Works with both proprietary (API-based) and open-source language models</p></li></ol><hr><h2 id="performance-results" tabindex="-1">Performance Results <a class="header-anchor" href="#performance-results" aria-label="Permalink to &quot;Performance Results&quot;">​</a></h2><h3 id="efficiency-gains-vs-react-baseline" tabindex="-1">Efficiency Gains (vs ReAct baseline) <a class="header-anchor" href="#efficiency-gains-vs-react-baseline" aria-label="Permalink to &quot;Efficiency Gains (vs ReAct baseline)&quot;">​</a></h3><ul><li><strong>Latency:</strong> Up to 3.7x speedup</li><li><strong>Cost:</strong> Up to 6.7x savings (token reduction)</li><li><strong>Accuracy:</strong> Improvement of up to ~9%</li></ul><h3 id="example-performance-metrics" tabindex="-1">Example Performance Metrics <a class="header-anchor" href="#example-performance-metrics" aria-label="Permalink to &quot;Example Performance Metrics&quot;">​</a></h3><ul><li>Reduced latency through parallel execution of independent tasks</li><li>Significantly lower token consumption due to elimination of sequential overhead</li><li>Improved accuracy from better orchestration of function calls</li></ul><hr><h2 id="methodology" tabindex="-1">Methodology <a class="header-anchor" href="#methodology" aria-label="Permalink to &quot;Methodology&quot;">​</a></h2><p>The system operates through the following workflow:</p><ol><li><strong>Planning Phase:</strong> LLM analyzes the problem and generates an execution plan with task dependencies</li><li><strong>Scheduling Phase:</strong> Tasks are scheduled according to dependencies and available parallelism</li><li><strong>Execution Phase:</strong> Independent tasks run in parallel; dependent tasks wait for prerequisites</li><li><strong>Aggregation Phase:</strong> Results are collected and passed to the LLM for further reasoning if needed</li></ol><hr><h2 id="experimental-evaluation" tabindex="-1">Experimental Evaluation <a class="header-anchor" href="#experimental-evaluation" aria-label="Permalink to &quot;Experimental Evaluation&quot;">​</a></h2><p>Testing demonstrates consistent performance gains across multiple benchmarks and scenarios:</p><ul><li>Complex multi-step reasoning tasks</li><li>Tool-use scenarios requiring multiple API calls</li><li>Long-horizon agent tasks</li><li>General question-answering with function calls</li></ul><hr><h2 id="practical-impact" tabindex="-1">Practical Impact <a class="header-anchor" href="#practical-impact" aria-label="Permalink to &quot;Practical Impact&quot;">​</a></h2><ol><li><strong>Cost Reduction:</strong> Significant savings in API calls and token consumption for applications requiring multiple function calls</li><li><strong>Latency Improvement:</strong> Faster response times for complex multi-step tasks</li><li><strong>Scalability:</strong> Enables more complex tasks feasible within latency budgets</li><li><strong>Accuracy:</strong> Better reasoning about task dependencies and parallel execution</li></ol><hr><h2 id="code-availability" tabindex="-1">Code Availability <a class="header-anchor" href="#code-availability" aria-label="Permalink to &quot;Code Availability&quot;">​</a></h2><p>The authors have made their implementation publicly accessible through GitHub at: <a href="https://github.com/SqueezeAILab/LLMCompiler" target="_blank" rel="noreferrer">https://github.com/SqueezeAILab/LLMCompiler</a></p><hr><h2 id="related-work" tabindex="-1">Related Work <a class="header-anchor" href="#related-work" aria-label="Permalink to &quot;Related Work&quot;">​</a></h2><p>LLMCompiler connects to research in:</p><ul><li>Agent architectures and orchestration</li><li>Parallel task execution</li><li>Compiler design principles applied to LLMs</li><li>Tool-use and function calling in language models</li></ul><hr><h2 id="implications" tabindex="-1">Implications <a class="header-anchor" href="#implications" aria-label="Permalink to &quot;Implications&quot;">​</a></h2><p>The work demonstrates that applying classical compiler design principles to LLM-based systems can yield substantial practical benefits. By enabling parallel execution of independent function calls, LLMCompiler provides a pathway to more efficient and capable AI agents while maintaining compatibility with existing LLM APIs.</p><hr><h2 id="venue" tabindex="-1">Venue <a class="header-anchor" href="#venue" aria-label="Permalink to &quot;Venue&quot;">​</a></h2><p>Proceedings of the 41st International Conference on Machine Learning (ICML), Vienna, Austria, 2024</p>',46)])])}const d=a(n,[["render",o]]);export{m as __pageData,d as default};
